  Artigo 3.º Aditamento à lei geral tributária
                            
                           
                             
                               
                             
     É aditado o n.º 10 ao artigo 89.º-A da lei geral tributária, aprovada ','439');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('pelo Decreto-Lei n.º 398/98, de 17 de Dezembro, com a seguinte redacção: 
